import sympy
import itertools
def a(n):
    count = 0
    for coeffs in itertools.product(range(n + 1), repeat=n):
        def f(x):
            return 1 + sum(c * (x ** (i + 1)) for i, c in enumerate(coeffs))
        if all(sympy.isprime(f(x)) for x in range(1, n + 1)):
            count += 1
    return count
